        [string]$Version,

        [Parameter(Mandatory)]
        [ValidateSet("major","minor","patch")]
        [string]$BumpType
    )

    if ($Version -notmatch '^\d+\.\d+\.\d+') {
        throw "Invalid semantic version: '$Version'. Expected format: X.Y.Z"
    }

    $parts = $Version -split '\.'
    [int]$major = $parts[0]
    [int]$minor = $parts[1]
    [int]$patch = $parts[2] -replace '[^0-9].*', ''   # strip pre-release suffix if any

    switch ($BumpType) {
        "major" { $major++; $minor = 0; $patch = 0 }
        "minor" { $minor++; $patch = 0 }
        "patch" { $patch++ }
    }

    return "$major.$minor.$patch"
}

# ─────────────────────────────────────────────────────────────
# Set-Version
# Writes the new version back to the file (plain text or JSON).
# ─────────────────────────────────────────────────────────────
function Set-Version {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$VersionFile,

        [Parameter(Mandatory)]
        [string]$NewVersion
    )

    $content = Get-Content $VersionFile -Raw
    $trimmed = $content.Trim()

    if ($trimmed.StartsWith("{")) {
        $json = $trimmed | ConvertFrom-Json
        $json.version = $NewVersion
        $json | ConvertTo-Json -Depth 10 | Set-Content $VersionFile -NoNewline
    } else {
        $NewVersion | Set-Content $VersionFile -NoNewline
    }
}

# ─────────────────────────────────────────────────────────────
# New-ChangelogEntry
# Creates a markdown-formatted changelog section for the release.
# ─────────────────────────────────────────────────────────────
function New-ChangelogEntry {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Version,

        [string[]]$Commits,

        [string]$Date = (Get-Date -Format "yyyy-MM-dd")
    )

    $lines = @("## [$Version] - $Date", "")

    # Group commits by type for a cleaner changelog
    $breaking  = @()
    $features  = @()
    $fixes     = @()
    $other     = @()

    foreach ($c in $Commits) {
        if ($c -match '^[a-zA-Z]+(\([^)]*\))?!:' -or $c -match 'BREAKING CHANGE:') {
            $breaking += "- $c"
        } elseif ($c -match '^feat(\([^)]*\))?:') {
            $features += "- $($c -replace '^feat(\([^)]*\))?:\s*', '')"
        } elseif ($c -match '^fix(\([^)]*\))?:') {
            $fixes += "- $($c -replace '^fix(\([^)]*\))?:\s*', '')"
        } else {
            $other += "- $c"
        }
    }

    if ($breaking.Count -gt 0) {
        $lines += "### Breaking Changes"
        $lines += $breaking
        $lines += ""
    }
    if ($features.Count -gt 0) {
        $lines += "### Features"
        $lines += $features
        $lines += ""
    }
    if ($fixes.Count -gt 0) {
        $lines += "### Bug Fixes"
        $lines += $fixes
        $lines += ""
    }
    if ($other.Count -gt 0) {
        $lines += "### Other"
        $lines += $other
        $lines += ""
    }

    return $lines -join "`n"
}

# ─────────────────────────────────────────────────────────────
# Invoke-SemanticVersionBump  (orchestrator / end-to-end)
# Reads the version file, determines bump, updates the file,
# generates a changelog, and returns a result object.
# ─────────────────────────────────────────────────────────────
function Invoke-SemanticVersionBump {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$VersionFile,

        [string[]]$Commits = @(),

        [string]$Date = (Get-Date -Format "yyyy-MM-dd")
    )

    $current  = Get-CurrentVersion -VersionFile $VersionFile
    $bumpType = Get-BumpType -Commits $Commits
    $newVer   = Invoke-VersionBump -Version $current -BumpType $bumpType
    Set-Version -VersionFile $VersionFile -NewVersion $newVer
    $changelog = New-ChangelogEntry -Version $newVer -Commits $Commits -Date $Date

    return [PSCustomObject]@{
        OldVersion = $current
        NewVersion = $newVer
        BumpType   = $bumpType
        Changelog  = $changelog
    }
}

# ─────────────────────────────────────────────────────────────
# Script entry point — run when executed directly (not dot-sourced)
# ─────────────────────────────────────────────────────────────
if ($MyInvocation.InvocationName -ne '.') {
    param(
        [string]$VersionFile = "version.txt",
        [string]$CommitFile  = "",   # optional path to a newline-delimited commit log
        [string]$Date        = (Get-Date -Format "yyyy-MM-dd")
    )

    $commits = @()
    if ($CommitFile -and (Test-Path $CommitFile)) {
        $commits = Get-Content $CommitFile
    }

    $result = Invoke-SemanticVersionBump -VersionFile $VersionFile -Commits $commits -Date $Date

    Write-Output "NEW_VERSION=$($result.NewVersion)"
    Write-Output "BUMP_TYPE=$($result.BumpType)"
    Write-Output ""
    Write-Output $result.Changelog
}

